#!/usr/bin/env node
/**
 * POSITIONING GUARDRAIL (privacy-browser drift) — defense-in-depth.
 * This site is generated by the shared growth-engine that once drifted
 * invisibleexit.com into privacy / anonymous-browsing positioning. This gate fails
 * the build (blocking deploy) if any deployed page, sitemap, or generator links to
 * or contains privacy-browser pSEO. This brand is NOT a privacy tool.
 * Self-contained (Vercel clones only this repo). See growth-engine/GUARDRAILS.md §2.
 *
 * NOTE: unlike invisibleexit's guard, /for/{privacy,journalism,research,legal}
 * are NOT blocked here — those can be legitimate audiences for these brands
 * (e.g. voicelogpro transcription for journalists/legal). Only universally-
 * privacy signals (browser comparisons, privacy glossary, anti-tracking) are blocked.
 */
import { readdirSync, readFileSync } from "node:fs";
import { join, extname } from "node:path";

const ROOT = process.cwd();

const FORBIDDEN_PATHS = /\/(?:vs|alternatives-to)\/(?:tor-browser|mullvad(?:-browser)?|brave|duckduckgo|incognito-mode|epic-browser|incogni|delete-me)\b|\/glossary\/(?:private-browsing|fingerprinting|dns-leak|webrtc-leak|session-isolation|tracking-protection|cookie-destruction|data-broker|digital-footprint|right-to-be-forgotten)\b|\/best\/(?:private-browsing-tools|anti-tracking-tools)\b/;
const FORBIDDEN_PHRASES = /anonymous session\s*&\s*private browsing|private[- ]browsing sessions?|isolated browsing sessions?|private sessions that auto-destroy|auto-destroy(?:s|ing)?\s+(?:history|cookies|all|session)|destroys?[^.<]{0,40}tracking data on exit|browser fingerprint|anti-tracking tool|private[- ]browsing tool|private-session tool|zero-trace browsing|session-level privacy/i;
const NEGATION = /\bnot\b|isn'?t\b|unrelated|never\b|rather than|instead of|does not/i;

const SKIP_DIRS = new Set(["node_modules","dist","dist-ssr","build",".git",".vercel",".github","src","og","assets","i18n","i18n_out","supabase","tests","test","coverage",".next"]);
const SCAN_EXT = new Set([".html",".xml",".txt",".py",".mjs",".sh"]);
const SKIP_FILES = new Set(["vercel.json","guard-positioning.mjs"]);

const violations = [];
function scanFile(path){
  const rel = path.replace(ROOT + "/", "");
  if (FORBIDDEN_PATHS.test("/" + rel.replace(/^public\//,""))) violations.push(rel + "  resurrected privacy-browser page");
  let text; try { text = readFileSync(path,"utf8"); } catch { return; }
  const lines = text.split("\n");
  for (let i=0;i<lines.length;i++){
    const line = lines[i];
    if (FORBIDDEN_PATHS.test(line)) violations.push(rel+":"+(i+1)+"  links to a privacy-browser page → "+line.trim().slice(0,110));
    if (FORBIDDEN_PHRASES.test(line) && !NEGATION.test(line)) violations.push(rel+":"+(i+1)+"  privacy-browser positioning → "+line.trim().slice(0,110));
  }
}
function walk(dir){
  let entries; try { entries = readdirSync(dir,{withFileTypes:true}); } catch { return; }
  for (const e of entries){
    if (e.isDirectory()){ if(!SKIP_DIRS.has(e.name)) walk(join(dir,e.name)); }
    else if (e.isFile() && !SKIP_FILES.has(e.name) && SCAN_EXT.has(extname(e.name))) scanFile(join(dir,e.name));
  }
}
walk(ROOT);

if (violations.length){
  console.error("\n🚨 POSITIONING GUARDRAIL FAILED — privacy/anonymous-browsing contamination:\n");
  for (const v of violations) console.error("   ✗ " + v);
  console.error("\n   " + violations.length + " violation(s). Build blocked. (see GUARDRAILS.md §2)\n");
  process.exit(1);
}
console.log("✅ positioning guard: no privacy/anonymous-browsing contamination");
